import{_ as t,o as a,c as i,a2 as n}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Chapter 12: Version Control Integration","description":"Integrating with Git for status, diff, commit, worktree, and automation workflows that make the agent a safe and effective collaborator on version-controlled code.","frontmatter":{"title":"Chapter 12: Version Control Integration","description":"Integrating with Git for status, diff, commit, worktree, and automation workflows that make the agent a safe and effective collaborator on version-controlled code."},"headers":[],"relativePath":"learn/linear/12-version-control-integration/index.md","filePath":"learn/linear/12-version-control-integration/index.md"}'),o={name:"learn/linear/12-version-control-integration/index.md"};function r(s,e,l,c,h,d){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="version-control-integration" tabindex="-1">Version Control Integration <a class="header-anchor" href="#version-control-integration" aria-label="Permalink to &quot;Version Control Integration&quot;">​</a></h1><p>This chapter covers the essential integration between a coding agent and Git, the version control system that underpins virtually all modern software development. An agent that modifies code must understand the state of the repository — which files are modified, what changes are staged, whether there are conflicts — and must be able to create commits, manage branches, and provide safety nets that let users confidently undo agent-generated changes.</p><p>We start with the Git object model: blobs, trees, commits, and refs. Understanding these fundamentals helps you reason about what Git operations actually do at the data level, which is essential for implementing features like intelligent diff display, conflict resolution, and repository analysis. You will then learn how to drive Git from Rust, both by spawning git commands (building on Chapter 7&#39;s process management) and by using the git2 library for direct access to the Git object database.</p><p>The chapter covers the full range of version control operations an agent needs: status checking, diff generation, commit creation, branch management, worktree mechanics for parallel workstreams, and merge conflict handling. We close with automation patterns — how to use Git as a safety net that makes agent modifications reversible, and how to build undo strategies that restore the repository to known-good states.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Understand the Git object model (blobs, trees, commits, refs) and how it enables version control operations</li><li>Drive Git operations from Rust using both process spawning and the git2 (libgit2) library</li><li>Implement status, diff, and commit operations that integrate smoothly into the agent workflow</li><li>Work with Git worktrees to enable parallel agent workstreams on the same repository</li><li>Handle merge conflicts programmatically and present resolution options to the user</li><li>Build Git-based safety nets and undo strategies for reversible agent modifications</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/12-version-control-integration/01-git-object-model.html">Git Object Model</a></li><li><a href="/linear/12-version-control-integration/02-working-with-git-in-rust.html">Working with Git in Rust</a></li><li><a href="/linear/12-version-control-integration/03-status-and-diff.html">Status and Diff</a></li><li><a href="/linear/12-version-control-integration/04-commit-operations.html">Commit Operations</a></li><li><a href="/linear/12-version-control-integration/05-branch-strategies.html">Branch Strategies</a></li><li><a href="/linear/12-version-control-integration/06-worktree-mechanics.html">Worktree Mechanics</a></li><li><a href="/linear/12-version-control-integration/07-merge-and-conflict.html">Merge and Conflict</a></li><li><a href="/linear/12-version-control-integration/08-repo-analysis-techniques.html">Repo Analysis Techniques</a></li><li><a href="/linear/12-version-control-integration/09-git-as-safety-net.html">Git as Safety Net</a></li><li><a href="/linear/12-version-control-integration/10-undo-strategies.html">Undo Strategies</a></li><li><a href="/linear/12-version-control-integration/11-automation-patterns.html">Automation Patterns</a></li><li><a href="/linear/12-version-control-integration/12-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 7 (process management for running git commands as child processes)</li></ul>',10)])])}const f=t(o,[["render",r]]);export{g as __pageData,f as default};
